import React, { Fragment , useState} from 'react';

const Login = ({setAuth}) => {
  return (
    <Fragment>
      <h1>Login</h1>
      <from>
        <input type="text" placeholder="Username" />
        <input type="password" placeholder="Password" />
        <button>Login</button>
      </from>
    </Fragment>
  );
};

export default Login;
